const axios = require('axios');

const BASE = 'https://api.deepseek.com/v1'; // OpenAI-compatible endpoint

const getKey = () => {
  const key = process.env.DEEPSEEK_API_KEY;
  if (!key) throw new Error('DEEPSEEK_API_KEY is not configured');
  return key;
};

const headers = () => ({
  Authorization: `Bearer ${getKey()}`,
  'Content-Type': 'application/json',
});

// OpenRouter model IDs → DeepSeek native model IDs.
// deepseek-chat and deepseek-reasoner are deprecated as of 2026-07-24;
// old aliases are forwarded to the v4 equivalents.
const MODEL_MAP = {
  'deepseek/deepseek-v4-pro':   'deepseek-v4-pro',
  'deepseek/deepseek-v4-flash': 'deepseek-v4-flash',
  // legacy aliases → v4
  'deepseek/deepseek-chat':     'deepseek-v4-flash',
  'deepseek/deepseek-r1':       'deepseek-v4-pro',
  'deepseek/deepseek-r1-0528':  'deepseek-v4-pro',
};

// Models that support the thinking / reasoning_effort parameters.
const REASONING_MODELS = new Set(['deepseek-v4-pro', 'deepseek-reasoner']);

function toNativeModelId(model) {
  return MODEL_MAP[model] ?? model.replace(/^deepseek\//, '');
}

// Normalise the frontend effort value to the two values the API actually accepts.
// API docs: only "high" and "max" are exposed; low/medium map to high on the
// client side before the request is sent.
function normaliseEffort(effort) {
  if (!effort || effort === 'none') return null;
  if (effort === 'max') return 'max';
  return 'high'; // covers 'low', 'medium', 'high'
}

/**
 * Send a chat completion request directly to DeepSeek's API.
 *
 * DeepSeek's API is OpenAI-compatible. Prefix caching is automatic — no
 * cache_control markers are needed (unlike the OpenRouter path).
 *
 * Reasoning is enabled by passing thinking: { type: "enabled" } alongside
 * reasoning_effort. Both are required — omitting thinking silently disables
 * the chain-of-thought even if reasoning_effort is present.
 * Valid effort values: "high" (default) | "max" (maximum).
 *
 * Cache telemetry: DeepSeek returns prompt_cache_hit_tokens and
 * prompt_cache_miss_tokens in every usage object. These are logged on every
 * response so cache hit rate can be monitored. Target: >80% for long-context
 * turns after the first. Cost: hit = $0.01/1M tokens, miss = $0.14/1M tokens.
 */
exports.chatCompletion = async ({ model, messages, max_tokens = 1024, temperature = 0.2, reasoning_effort }) => {
  const nativeModel = toNativeModelId(model);
  const body = { model: nativeModel, messages, max_tokens, temperature };

  const effort = normaliseEffort(reasoning_effort);
  if (effort && REASONING_MODELS.has(nativeModel)) {
    body.thinking = { type: 'enabled' };
    body.reasoning_effort = effort;
  }

  const res = await axios.post(`${BASE}/chat/completions`, body, {
    headers: headers(),
    timeout: 90000,
  });

  _logCacheMetrics(nativeModel, res.data.usage);

  return res.data;
};

/**
 * Log DeepSeek cache hit/miss telemetry from the usage object.
 * DeepSeek includes prompt_cache_hit_tokens and prompt_cache_miss_tokens on
 * every response. A hit rate below 80% for multi-turn sessions indicates the
 * prefix is changing between requests (check for dynamic content at the start
 * of the messages array).
 */
function _logCacheMetrics(model, usage) {
  if (!usage) return;
  const hit  = usage.prompt_cache_hit_tokens  ?? 0;
  const miss = usage.prompt_cache_miss_tokens ?? 0;
  const comp = usage.completion_tokens        ?? 0;
  const total = hit + miss;
  const hitPct = total > 0 ? Math.round((hit / total) * 100) : 0;
  console.log(
    `[deepseek] model=${model} ` +
    `cache_hit=${hit} cache_miss=${miss} completion=${comp} ` +
    `hit_rate=${hitPct}%${hit === 0 && miss > 0 ? ' (cold — first request or prefix changed)' : ''}`
  );
}

exports.toNativeModelId = toNativeModelId;
exports.normaliseEffort = normaliseEffort;

