const axios = require('axios');
const { listUserModels, chatCompletion, _applyCachingMarkers } = require('../../helpers/openrouter');

describe('openrouter helper', () => {
  beforeEach(() => {
    jest.clearAllMocks();
    process.env.OPENROUTER_API_KEY = 'sk-or-test-key';
  });
  afterEach(() => { delete process.env.OPENROUTER_API_KEY; });

  // ── listUserModels ──────────────────────────────────────────────────────────

  test('listUserModels calls /models with bearer token', async () => {
    axios.get.mockResolvedValue({ data: { data: [{ id: 'anthropic/claude-3.5-haiku' }] } });
    const result = await listUserModels();
    expect(axios.get).toHaveBeenCalledWith(
      'https://openrouter.ai/api/v1/models/user',
      expect.objectContaining({
        headers: expect.objectContaining({ Authorization: 'Bearer sk-or-test-key' }),
        timeout: 12000,
      })
    );
    expect(result.data[0].id).toBe('anthropic/claude-3.5-haiku');
  });

  test('listUserModels throws when OPENROUTER_API_KEY is missing', async () => {
    delete process.env.OPENROUTER_API_KEY;
    await expect(listUserModels()).rejects.toThrow('OPENROUTER_API_KEY is not configured');
  });

  test('listUserModels propagates HTTP errors from OpenRouter', async () => {
    axios.get.mockRejectedValue(Object.assign(new Error('Unauthorized'), { response: { status: 401 } }));
    await expect(listUserModels()).rejects.toMatchObject({ response: { status: 401 } });
  });

  // ── chatCompletion ──────────────────────────────────────────────────────────

  test('chatCompletion posts model + messages with defaults', async () => {
    axios.post.mockResolvedValue({ data: { choices: [{ message: { content: 'hi' } }] } });
    const result = await chatCompletion({
      model: 'deepseek/deepseek-chat',
      messages: [{ role: 'user', content: 'classify a vinyl figurine' }],
    });
    expect(axios.post).toHaveBeenCalledWith(
      'https://openrouter.ai/api/v1/chat/completions',
      expect.objectContaining({
        model: 'deepseek/deepseek-chat',
        messages: [{ role: 'user', content: 'classify a vinyl figurine' }],
        max_tokens: 1024,
        temperature: 0.2,
      }),
      expect.objectContaining({
        headers: expect.objectContaining({ Authorization: 'Bearer sk-or-test-key' }),
      })
    );
    expect(result.choices[0].message.content).toBe('hi');
  });

  test('chatCompletion throws when OPENROUTER_API_KEY is missing', async () => {
    delete process.env.OPENROUTER_API_KEY;
    await expect(chatCompletion({ model: 'x', messages: [] })).rejects.toThrow('OPENROUTER_API_KEY is not configured');
  });

  test('chatCompletion respects custom max_tokens and temperature', async () => {
    axios.post.mockResolvedValue({ data: { choices: [] } });
    await chatCompletion({
      model: 'qwen/qwen-2.5-72b-instruct',
      messages: [{ role: 'user', content: 'hi' }],
      max_tokens: 2048,
      temperature: 0.7,
    });
    expect(axios.post).toHaveBeenCalledWith(
      expect.any(String),
      expect.objectContaining({ max_tokens: 2048, temperature: 0.7 }),
      expect.any(Object)
    );
  });

  test('chatCompletion sends cached messages for anthropic models', async () => {
    axios.post.mockResolvedValue({ data: { choices: [] } });
    const messages = [
      { role: 'system', content: 'You are a specialist.' },
      { role: 'user', content: 'classify this' },
    ];
    await chatCompletion({ model: 'anthropic/claude-sonnet-4-5', messages });
    const body = axios.post.mock.calls[0][1];
    expect(Array.isArray(body.messages[0].content)).toBe(true);
    expect(body.messages[0].content[0]).toMatchObject({ type: 'text', cache_control: { type: 'ephemeral' } });
    expect(typeof body.messages[1].content).toBe('string');
  });

  test('chatCompletion sends cached messages for deepseek models', async () => {
    axios.post.mockResolvedValue({ data: { choices: [] } });
    const messages = [
      { role: 'system', content: 'System.' },
      { role: 'user', content: 'hi' },
    ];
    await chatCompletion({ model: 'deepseek/deepseek-chat', messages });
    const body = axios.post.mock.calls[0][1];
    expect(Array.isArray(body.messages[0].content)).toBe(true);
    expect(body.messages[0].content[0].cache_control).toEqual({ type: 'ephemeral' });
  });

  test('chatCompletion sends cached messages for google models', async () => {
    axios.post.mockResolvedValue({ data: { choices: [] } });
    const messages = [
      { role: 'system', content: 'System.' },
      { role: 'user', content: 'hi' },
    ];
    await chatCompletion({ model: 'google/gemini-flash-1.5', messages });
    const body = axios.post.mock.calls[0][1];
    expect(Array.isArray(body.messages[0].content)).toBe(true);
    expect(body.messages[0].content[0].cache_control).toEqual({ type: 'ephemeral' });
  });

  test('chatCompletion passes openai messages through unchanged', async () => {
    axios.post.mockResolvedValue({ data: { choices: [] } });
    const messages = [
      { role: 'system', content: 'System.' },
      { role: 'user', content: 'hi' },
    ];
    await chatCompletion({ model: 'openai/gpt-4o', messages });
    const body = axios.post.mock.calls[0][1];
    expect(typeof body.messages[0].content).toBe('string');
  });
});

// ── _applyCachingMarkers ──────────────────────────────────────────────────────

describe('_applyCachingMarkers()', () => {
  const SYSTEM = { role: 'system',    content: 'System prompt.' };
  const USER1  = { role: 'user',      content: 'First question.' };
  const ASST1  = { role: 'assistant', content: 'First answer.' };
  const USER2  = { role: 'user',      content: 'Second question.' };

  // ── provider routing ───────────────────────────────────────────────────────

  test('applies markers for anthropic/* models', () => {
    const result = _applyCachingMarkers('anthropic/claude-sonnet-4-5', [SYSTEM, USER1]);
    expect(Array.isArray(result[0].content)).toBe(true);
  });

  test('applies markers for deepseek/* models', () => {
    const result = _applyCachingMarkers('deepseek/deepseek-chat', [SYSTEM, USER1]);
    expect(Array.isArray(result[0].content)).toBe(true);
  });

  test('applies markers for deepseek-r1 (reasoning model)', () => {
    const result = _applyCachingMarkers('deepseek/deepseek-r1', [SYSTEM, USER1]);
    expect(Array.isArray(result[0].content)).toBe(true);
  });

  test('applies markers for google/* models', () => {
    const result = _applyCachingMarkers('google/gemini-flash-1.5', [SYSTEM, USER1]);
    expect(Array.isArray(result[0].content)).toBe(true);
  });

  test('returns messages unchanged for openai/* models', () => {
    const msgs = [SYSTEM, USER1];
    expect(_applyCachingMarkers('openai/gpt-4o', msgs)).toEqual(msgs);
  });

  test('returns messages unchanged for meta-llama/* models', () => {
    const msgs = [SYSTEM, USER1];
    expect(_applyCachingMarkers('meta-llama/llama-3.3-70b-instruct', msgs)).toEqual(msgs);
  });

  test('returns messages unchanged for qwen/* models', () => {
    const msgs = [SYSTEM, USER1];
    expect(_applyCachingMarkers('qwen/qwen-2.5-72b-instruct', msgs)).toEqual(msgs);
  });

  // ── cache breakpoint logic (provider-agnostic — tested via anthropic) ──────

  test('converts system message content to a cached content block', () => {
    const result = _applyCachingMarkers('anthropic/claude-sonnet-4-5', [SYSTEM, USER1]);
    expect(result[0].content).toEqual([
      { type: 'text', text: 'System prompt.', cache_control: { type: 'ephemeral' } },
    ]);
  });

  test('does not modify user-role messages', () => {
    const result = _applyCachingMarkers('anthropic/claude-sonnet-4-5', [SYSTEM, USER1]);
    expect(result[1].content).toBe('First question.');
  });

  test('adds cache_control to the last assistant message', () => {
    const result = _applyCachingMarkers('anthropic/claude-sonnet-4-5', [SYSTEM, USER1, ASST1, USER2]);
    expect(result[2].content).toEqual([
      { type: 'text', text: 'First answer.', cache_control: { type: 'ephemeral' } },
    ]);
    expect(result[3].content).toBe('Second question.');
  });

  test('caches only the LAST assistant message when there are multiple', () => {
    const ASST2 = { role: 'assistant', content: 'Second answer.' };
    const USER3 = { role: 'user', content: 'Third question.' };
    const result = _applyCachingMarkers('anthropic/claude-sonnet-4-5', [SYSTEM, USER1, ASST1, USER2, ASST2, USER3]);
    expect(typeof result[2].content).toBe('string');
    expect(Array.isArray(result[4].content)).toBe(true);
    expect(result[4].content[0].cache_control).toEqual({ type: 'ephemeral' });
  });

  test('handles messages with no system role', () => {
    const result = _applyCachingMarkers('anthropic/claude-sonnet-4-5', [USER1, ASST1, USER2]);
    expect(typeof result[0].content).toBe('string');
    expect(Array.isArray(result[1].content)).toBe(true);
  });

  test('handles messages with no assistant role (first turn)', () => {
    const result = _applyCachingMarkers('anthropic/claude-sonnet-4-5', [SYSTEM, USER1]);
    expect(Array.isArray(result[0].content)).toBe(true);
    expect(typeof result[1].content).toBe('string');
  });

  test('does not mutate the original messages array', () => {
    const msgs = [{ ...SYSTEM }, { ...USER1 }];
    _applyCachingMarkers('anthropic/claude-sonnet-4-5', msgs);
    expect(typeof msgs[0].content).toBe('string');
  });
});

