import { Component, OnInit } from '@angular/core';
import { MatSnackBar } from '@angular/material/snack-bar';
import { firstValueFrom } from 'rxjs';
import { AiSettingsService, OpenRouterModel } from '../../../helpers/services/ai-settings.service';

type ApiBackend = 'openrouter' | 'deepseek-direct';

@Component({
  selector: 'app-ai-settings',
  templateUrl: './ai-settings.component.html',
  styleUrls: ['./ai-settings.component.scss'],
  standalone: false,
})
export class AiSettingsComponent implements OnInit {
  selectedApi: ApiBackend = 'openrouter';
  models: OpenRouterModel[] = [];
  selectedModelId: string | null = null;
  selectedEffort: 'none' | 'high' | 'max' = 'max';
  loadingModels = false;
  saving = false;
  error = '';

  constructor(
    private aiSettings: AiSettingsService,
    private snackbar: MatSnackBar,
  ) {}

  async ngOnInit() {
    // Load all three saved settings first, then fetch the model list for the
    // saved API. If the saved model isn't in the new API's catalog we drop it
    // so the dropdown doesn't show a stale selection.
    try {
      const [apiRes, modelRes, effortRes] = await Promise.all([
        firstValueFrom(this.aiSettings.getCurrentApi()),
        firstValueFrom(this.aiSettings.getCurrentModel()),
        firstValueFrom(this.aiSettings.getReasoningEffort()),
      ]);
      const savedApi = apiRes?.value;
      if (savedApi === 'openrouter' || savedApi === 'deepseek-direct') {
        this.selectedApi = savedApi;
      }
      this.selectedModelId = modelRes?.value ?? null;
      const eff = effortRes?.value;
      if (eff === 'none' || eff === 'high' || eff === 'max') this.selectedEffort = eff;
    } catch (err: any) {
      this.error = `Failed to load settings: ${err?.message ?? 'Unknown error'}.`;
    }
    await this.loadModels();
  }

  /**
   * Fetch the model list for the currently-selected API.
   * Drops the saved model selection if it doesn't appear in the new list,
   * to prevent showing a model that won't actually work via the chosen API.
   */
  private async loadModels() {
    this.loadingModels = true;
    this.error = '';
    try {
      const res = await firstValueFrom(this.aiSettings.getAvailableModels(this.selectedApi));
      this.models = res?.data ?? [];
      if (this.selectedModelId && !this.models.some(m => m.id === this.selectedModelId)) {
        this.selectedModelId = null;
      }
    } catch (err: any) {
      this.error = `Failed to load models: ${err?.message ?? 'Unknown error'}. ` +
        (this.selectedApi === 'openrouter'
          ? 'Make sure OPENROUTER_API_KEY is set in Cloud Run.'
          : 'Make sure DEEPSEEK_API_KEY is set in Cloud Run.');
    } finally {
      this.loadingModels = false;
    }
  }

  /** Called when the API dropdown changes — reloads the model list. */
  async onApiChange(api: ApiBackend) {
    this.selectedApi = api;
    await this.loadModels();
  }

  get selectedModel(): OpenRouterModel | undefined {
    return this.models.find(m => m.id === this.selectedModelId);
  }

  /** True for models that support DeepSeek's thinking mode. */
  get supportsReasoning(): boolean {
    return this.selectedModelId === 'deepseek/deepseek-v4-pro'
      || this.selectedModelId === 'deepseek/deepseek-r1'
      || this.selectedModelId === 'deepseek/deepseek-r1-0528';
  }

  formatPrice(pricePerMillion: string | undefined): string {
    if (!pricePerMillion) return '?';
    const n = parseFloat(pricePerMillion) * 1_000_000;
    return `$${n.toFixed(2)}/1M`;
  }

  async save() {
    if (!this.selectedModelId) { return; }
    this.saving = true;
    try {
      await Promise.all([
        firstValueFrom(this.aiSettings.saveApi(this.selectedApi)),
        firstValueFrom(this.aiSettings.saveModel(this.selectedModelId)),
        firstValueFrom(this.aiSettings.saveReasoningEffort(this.selectedEffort)),
      ]);
      this.snackbar.open('AI settings saved', 'OK', { duration: 2000 });
    } catch (err: any) {
      this.snackbar.open(`Save failed: ${err?.message ?? 'Unknown error'}`, 'OK', { duration: 4000 });
    } finally {
      this.saving = false;
    }
  }
}

