/** Shape returned by POST /api/openrouter/chat (proxied OpenAI / DeepSeek response). */
interface ChatApiResponse {
  choices?: Array<{
    message?: {
      content?: string;
      /** DeepSeek native chain-of-thought field. */
      reasoning_content?: string;
      /** OpenRouter sometimes flattens DeepSeek's reasoning into `reasoning`. */
      reasoning?: string;
    };
  }>;
  usage?: ChatUsage;
