  // ── CROSS lookup ────────────────────────────────────────────────────────────

  toggleCross() {
    this.showCross = !this.showCross;
    if (!this.showCross) {
      this.crossResults = [];
      this.crossError = '';
    }
  }

  async searchCross() {
    const term = this.crossTerm.trim();
    if (!term) { return; }
    this.crossLoading = true;
    this.crossError = '';
    this.crossResults = [];
    try {
      const res = await firstValueFrom(this.crossService.search(term, 20));
      this.crossResults = res.rulings ?? [];
      this.crossTotal = res.totalRulings ?? 0;
      if (this.crossResults.length === 0) {
        this.crossError = 'No rulings found. Try a different HTS code or product description.';
      }
    } catch {
      this.crossError = 'CROSS lookup failed. Check your connection and try again.';
    } finally {
      this.crossLoading = false;
    }
  }

  openRuling(rulingNumber: string) {
    window.open(`https://rulings.cbp.gov/ruling/${rulingNumber}`, '_blank', 'noopener');
  }

  onCrossKeydown(event: KeyboardEvent) {
    if (event.key === 'Enter') { this.searchCross(); }
  }

  // ── AI classification panel ─────────────────────────────────────────────────

  async toggleAi() {
    this.showAi = !this.showAi;
    if (this.showAi && !this.aiInitialised) {
      await this.initAiSession();
    }
  }

  /**
   * Initialise the AI session:
   * 1. Clean the product description
   * 2. Search CROSS with the cleaned description (reuses existing results if present)
   * 3. Fetch the configured AI model
   * 4. Send the initial classification request
   */
  private async initAiSession() {
    this.aiInitialised = true;
    this.aiError = '';
    this.aiLoading = true; // show spinner immediately — settings fetch + CROSS search happen before callAi

    try {
      // 1. Clean description
      const rawDesc = this.data.desc ?? '';
      this.cleanedDesc = cleanDescForHts(rawDesc, this.data.licenses ?? []);

      if (!this.cleanedDesc) {
        this.aiError = 'No product description available on this row. Add a description and try again.';
        return;
      }

      // 2. Fetch API + model + reasoning effort from settings
      try {
        const [apiSetting, modelSetting, effortSetting] = await Promise.all([
          firstValueFrom(this.aiSettings.getCurrentApi()),
          firstValueFrom(this.aiSettings.getCurrentModel()),
          firstValueFrom(this.aiSettings.getReasoningEffort()),
        ]);
        const savedApi = apiSetting?.value;
        if (savedApi === 'openrouter' || savedApi === 'deepseek-direct') {
          this.aiApi = savedApi;
        }
        this.aiModel = modelSetting?.value ?? '';
        const savedEffort = effortSetting?.value;
        if (savedEffort === 'none' || savedEffort === 'high' || savedEffort === 'max') {
          this.reasoningEffort = savedEffort;
        }
      } catch {
        this.aiError = 'Could not load AI model setting. Configure it in Editor → AI Settings.';
        return;
      }

      if (!this.aiModel) {
        this.aiError = 'No AI model configured. Go to Editor → AI Settings to select a model.';
        return;
      }

      // 2b. Resolve model pricing for cost tracking (non-fatal if unavailable)
      try {
        const modelInfo = await firstValueFrom(
          this.aiSettings.getModelInfo(this.aiModel, this.aiApi ?? 'openrouter'),
        );
        if (modelInfo?.pricing) {
          const p = modelInfo.pricing;
          this.modelPricing = {
            inputPerToken:    parseFloat(p.prompt)        || 0,
            outputPerToken:   parseFloat(p.completion)    || 0,
            cacheHitPerToken: parseFloat(p.prompt_cache ?? '0') || 0,
          };
        }
      } catch { /* pricing unavailable — cost display will be hidden */ }

    // 3. Search CROSS — first attempt with the full cleaned description, then
    // ask the AI to suggest shorter terms (removing the least HTS-relevant words
    // first) if the first attempt returns nothing. Naive leading-word-drop is
    // wrong because important words (material, product type) can appear anywhere.
    if (this.crossResults.length === 0 && this.cleanedDesc) {
      // First attempt: cleaned description as-is
      try {
        const res = await firstValueFrom(this.crossService.search(this.cleanedDesc, 20));
        const rulings = res.rulings ?? [];
        if (rulings.length > 0) {
          this.crossResults = rulings;
          this.crossTotal   = res.totalRulings ?? 0;
          this.crossTerm    = this.cleanedDesc;
        }
      } catch { /* non-fatal */ }

      // Second attempt: AI-suggested shorter terms, preserving classification-relevant words
      if (this.crossResults.length === 0) {
        try {
          const terms = await firstValueFrom(
            this.htsClassifier.suggestCrossTerms(this.cleanedDesc, this.aiModel, this.aiApi),
          );
          for (const term of terms) {
            try {
              const res = await firstValueFrom(this.crossService.search(term, 20));
              const rulings = res.rulings ?? [];
              if (rulings.length > 0) {
                this.crossResults = rulings;
                this.crossTotal   = res.totalRulings ?? 0;
                this.crossTerm    = term;
                break;
              }
            } catch { /* non-fatal — try next term */ }
          }
        } catch { /* AI term suggestion failed — proceed without CROSS */ }
      }
    }

    // 4. Build initial messages with all known row context so the model can skip
    //    questions about facts we already have. Include FOB country (signals
    //    Section 301 applicability for China), existing breakdown components, and
    //    Trump 2025 rate when already populated.
    const knownContext: Record<string, string> = {};
    if (this.fobCountry) {
      knownContext['FOB country (country of manufacture)'] = this.fobCountry;
    }
    if (this.trump2025Result?.found && this.trump2025Result.rate != null) {
      knownContext['Trump 2025 reciprocal tariff'] =
        `${this.trump2025Result.rate}% (already confirmed for ${this.trump2025Result.country})`;
    }

    this.aiMessages = this.htsClassifier.buildInitialMessages(
      this.cleanedDesc, this.crossResults, knownContext,
    );
    await this.callAi();
  } finally {
    // callAi() resets aiLoading in its own finally. Clear it here only if we
    // returned early (before callAi was reached) and left the spinner running.
    if (this.aiLoading && this.aiError) {
      this.aiLoading = false;
    }
  }
  }

  /** Keeps the chatInput string in sync with the native input element. */
  onChatInput(event: Event) {
    this.chatInput = (event.target as HTMLInputElement).value;
  }

  onChatKeydown(event: KeyboardEvent) {
    if (event.key === 'Enter' && !event.shiftKey) {
      event.preventDefault();
      this.sendChatMessage();
    }
  }

  async sendChatMessage() {
    const text = this.chatInput.trim();
    if (!text || this.aiLoading) { return; }
    this.chatInput = '';
    this.chatTurns.push({ role: 'user', text });
    this.aiMessages.push({ role: 'user', content: text });
    await this.callAi();
  }

  /** Estimate USD cost for one API response from accumulated usage. Returns 0 when pricing unavailable. */
  private computeTurnCost(usage: ChatUsage | null | undefined): number {
    if (!this.modelPricing || !usage) return 0;
    const { inputPerToken, outputPerToken, cacheHitPerToken } = this.modelPricing;
    const hit  = usage.prompt_cache_hit_tokens  ?? 0;
    const miss = usage.prompt_cache_miss_tokens ?? 0;
    const comp = usage.completion_tokens ?? 0;
    const promptCost = (hit > 0 || miss > 0)
      ? hit * cacheHitPerToken + miss * inputPerToken
      : (usage.prompt_tokens ?? 0) * inputPerToken;
    return promptCost + comp * outputPerToken;
  }

  /**
   * Accumulator for usage and reasoning across confidence-retry calls.
   * A single "user-visible" turn may span multiple API calls behind the scenes
   * (e.g. confidence=medium → auto-retry). We pin the data to the turn that
   * actually gets shown, so the cost displayed reflects the true cost of the answer.
   */
  private pendingUsage: ChatUsage | null = null;
  private pendingReasoning: string[] = [];

  private async callAi(confidenceRetry = 0) {
    this.aiLoading = true;
    this.aiError = '';
    if (confidenceRetry === 0) {
      this.pendingUsage = null;
      this.pendingReasoning = [];
    }
    try {
      const result = await firstValueFrom(this.htsClassifier.chat(this.aiModel, this.aiMessages, this.reasoningEffort, this.aiApi));
      const parsed = this.htsClassifier.parseResponse(result.content);
      this.aiMessages.push({ role: 'assistant', content: result.content });

      // Accumulate cost and chain-of-thought across silent retries.
      this.pendingUsage = addUsage(this.pendingUsage, result.usage);
      if (result.reasoningContent) this.pendingReasoning.push(result.reasoningContent);

      // Safety net: if the model returns medium/low confidence despite the system
      // prompt rule, automatically ask it to keep questioning. Cap at 4 retries
      // to prevent infinite loops — after that, show whatever it returned.
      if (parsed.type === 'classification' && parsed.confidence !== 'high' && confidenceRetry < 4) {
        this.aiMessages.push({
          role: 'user',
          content: `Your confidence is "${parsed.confidence}". Please ask one more clarifying question before giving the final classification.`,
        });
        await this.callAi(confidenceRetry + 1);
        return;
      }

      if (parsed.type === 'classification') {
        const turnCost = this.computeTurnCost(this.pendingUsage);
        this.sessionCostUsd += turnCost;
        const turn: ChatTurn = {
          role: 'ai',
          text: parsed.reasoning,
          classification: parsed,
          reasoningContent: this.pendingReasoning.join('\n\n---\n\n'),
          usage: this.pendingUsage,
          cost: this.modelPricing ? turnCost : null,
        };
        this.chatTurns.push(turn);

        // Look up Section 301 data — non-fatal if not configured
        try {
          const s301 = await firstValueFrom(this.aiSettings.lookupSection301(parsed.hts_code));
          turn.section301 = s301;
        } catch {
          turn.section301 = null; // no data uploaded yet
        }

        // Look up authoritative MFN base rate from bundled USITC HTS data.
        // 404 (code not in schedule) is mapped to a found:false result so the
        // applyClassification flow can still fall back to the model's guess.
        try {
          const rate = await firstValueFrom(
            this.aiSettings.lookupHtsRate(parsed.hts_code).pipe(
              catchError(() => of<HtsRateResult>({
                found: false, hts: null, rate: null, rateText: null, description: null, matchType: null,
              })),
            ),
          );
          turn.htsRate = rate;
          if (rate?.rateText) {
            turn.parsedCompound = parseCompoundRate(rate.rateText);
          }
        } catch {
          turn.htsRate = null;
        }
      } else {
        const turnCost = this.computeTurnCost(this.pendingUsage);
        this.sessionCostUsd += turnCost;
        this.chatTurns.push({
          role: 'ai',
          text: parsed.text,
          reasoningContent: this.pendingReasoning.join('\n\n---\n\n'),
          usage: this.pendingUsage,
          cost: this.modelPricing ? turnCost : null,
        });
      }

      this.scrollChatToBottom();
    } catch (err: any) {
      this.aiError = err?.error?.error ?? err?.message ?? 'AI request failed. Check your OpenRouter API key and try again.';
    } finally {
      this.aiLoading = false;
    }
  }

  /**
   * Apply the suggested duty rate from the AI classification to the form.
   *
   * Sources for the MFN base rate, in priority order:
   *   1. Authoritative lookup against the bundled USITC HTS schedule
   *   2. The model's own suggested_duty_pct (used only as a fallback when the
   *      schedule lookup misses OR returns a non-ad-valorem rate we can't sum)
   *
   * Section 301 (when found) is added on top of the MFN rate.
   */
  applyClassification(turn: ChatTurn) {
    if (!this.canEditDuty) return; // sales role guard
    const s301 = turn.section301;
    const hts  = turn.htsRate;

    // MFN comes only from the authoritative USITC schedule. We previously
    // fell back to the model's suggested_duty_pct when the lookup missed,
    // but the model returned values like 0.039 (decimal fractions) which
    // produced "0.039%" in the cell. The model is unreliable for numbers —
    // when the schedule misses, leave MFN blank and let the user enter it.
    const compound = turn.parsedCompound;

    let mfn = 0;
    let mfnLabel = '';
    let dollarPatch: string | null = null;

    if (hts?.found && hts.rate != null) {
      // Pure ad-valorem rate from USITC schedule
      mfn = hts.rate;
      const via = hts.matchType === 'exact'  ? ''
                : hts.matchType === 'prefix8' ? ` (via 8-digit parent ${hts.hts})`
                : hts.matchType === 'prefix6' ? ` (via 6-digit parent ${hts.hts})`
                : hts.matchType === 'prefix4' ? ` (via 4-digit heading ${hts.hts} — all subheadings share this rate)`
                : '';
      mfnLabel = `${mfn}% MFN${via}`;
    } else if (hts?.matchType === 'prefix4-ambiguous') {
      mfnLabel = `MFN: heading ${hts.hts} has subheadings with different rates — enter manually`;
    } else if (hts?.found && hts.rate === null && compound && compound.percent !== null) {
      // Compound rate: we extracted the % part (e.g. "3.4% + $0.25/pc" → 3.4%)
      mfn = compound.percent;
      mfnLabel = `${mfn}% MFN (from compound rate: ${hts.rateText})`;
      if (compound.dollarPerPiece != null) {
        dollarPatch = String(compound.dollarPerPiece);
        mfnLabel += ` + $${compound.dollarPerPiece}/pc (applied to $ field)`;
      } else if (compound.hasNonPieceSpecific) {
        mfnLabel += ` — non-per-piece specific duty (${hts.rateText}) not auto-filled, enter in $ field manually`;
      }
    } else if (hts?.found && hts.rateText) {
      mfnLabel = `MFN: ${hts.rateText} (non-ad-valorem — enter the equivalent percent manually)`;
    } else {
      mfnLabel = 'MFN: not in bundled USITC schedule — verify the HTS code and enter the rate manually';
    }

    const s301Rate  = s301?.found && s301.rate != null ? s301.rate : 0;
    const trumpRate = this.trump2025Result?.found && this.trump2025Result.rate != null
                      ? this.trump2025Result.rate
                      : (parseFloat(this.form.value.trump2025Rate) || 0);

    const patch: Record<string, string> = {
      mfnRate:        String(mfn),
      section301Rate: String(s301Rate),
      trump2025Rate:  String(trumpRate),
    };
    if (dollarPatch !== null) patch['dollarAmount'] = dollarPatch;
    this.form.patchValue(patch);

    const total     = mfn + s301Rate + trumpRate;
    const s301Part  = s301?.found ? ` + ${s301Rate}% Section 301 (${s301.list})` : '';
    const trumpPart = trumpRate ? ` + ${trumpRate}% Trump 2025 (${this.trump2025Result?.country ?? this.fobCountry ?? '?'})` : '';

    this._snakcbar.open(
      `Applied ${mfnLabel}${s301Part}${trumpPart} = ${total}% total`,
      'close',
      { duration: 8000 },
    );
  }

  confidenceClass(c: HtsClassification['confidence']): string {
    return { high: 'conf-high', medium: 'conf-medium', low: 'conf-low' }[c] ?? '';
  }

  private scrollChatToBottom() {
    setTimeout(() => {
      this.chatBottom?.nativeElement?.scrollIntoView({ behavior: 'smooth' });
    }, 50);
  }
