        {{ showAi ? 'Hide AI classifier' : 'Classify with AI (HTS)' }}
      </button>

      @if (showAi) {
        <!-- Cleaned description preview -->
        @if (cleanedDesc) {
          <div class="ai-desc-preview">
            <span class="ai-desc-label">Classifying:</span>
            <span class="ai-desc-text">{{ cleanedDesc }}</span>
          </div>
        }

        <!-- Reasoning effort selector — locked once session starts -->
        <div class="ai-effort-row">
          <span class="ai-effort-label">Reasoning effort</span>
          <select [(ngModel)]="reasoningEffort" [disabled]="aiInitialised" class="ai-effort-select"
                  [title]="aiInitialised ? 'Start a new dialog session to change effort' : 'Set before classification starts'">
            <option value="none">None</option>
            <option value="high">High</option>
            <option value="max">Max</option>
          </select>
          @if (aiInitialised) {
            <span class="ai-effort-locked">locked</span>
          }
        </div>

        <!-- Error state -->
        @if (aiError) {
          <p class="ai-error">{{ aiError }}</p>
        }

        <!-- Chat messages -->
        @if (chatTurns.length > 0) {
          <div class="ai-chat">
            @for (turn of chatTurns; track $index) {
              <div class="chat-turn" [class.user-turn]="turn.role === 'user'" [class.ai-turn]="turn.role === 'ai'">

                <!-- Classification result card -->
                @if (turn.classification) {
                  <div class="classification-card">
                    <div class="class-header">
                      <span class="hts-code">{{ turn.classification.hts_code }}</span>
                      <span class="conf-badge" [class]="confidenceClass(turn.classification.confidence)">
                        {{ turn.classification.confidence }} confidence
                      </span>
                    </div>
                    <p class="hts-desc">{{ turn.classification.hts_description }}</p>
                    <p class="class-reasoning">{{ turn.classification.reasoning }}</p>

                    <!-- Duty rates -->
                    <div class="rates-row">
                      <!-- MFN: authoritative USITC lookup. We never use the model's
                           suggested_duty_pct anymore — too unreliable (returned 0.039
                           instead of 3.9, etc.). If the schedule misses, surface the
                           miss clearly so the user can verify the HTS code. -->
                      @if (turn.htsRate?.found && turn.htsRate!.rate !== null) {
                        <span class="rate-item">
                          MFN: <strong>{{ turn.htsRate!.rate }}%</strong>
                          <span class="rate-src"
                                title="From bundled USITC HTS schedule{{ turn.htsRate!.matchType !== 'exact' ? ' — matched via ' + turn.htsRate!.hts : '' }}"
                          >USITC{{ turn.htsRate!.matchType === 'prefix4' ? ' (heading)' : turn.htsRate!.matchType === 'prefix8' ? ' (8-digit)' : turn.htsRate!.matchType === 'prefix6' ? ' (6-digit)' : '' }}</span>
                        </span>
                      } @else if (turn.htsRate?.matchType === 'prefix4-ambiguous') {
                        <span class="rate-item">
                          MFN: <strong>?</strong>
                          <span class="rate-note">heading {{ turn.htsRate!.hts }} has multiple rates — enter MFN manually</span>
                        </span>
                      } @else if (turn.htsRate?.found && turn.htsRate!.rateText && turn.parsedCompound?.percent !== null && turn.parsedCompound?.percent !== undefined) {
                        <!-- Compound rate: % extracted automatically; $ component may also be auto-filled -->
                        <span class="rate-item">
                          MFN: <strong>{{ turn.parsedCompound!.percent }}%</strong>
                          @if (turn.parsedCompound!.dollarPerPiece != null) {
                            <span class="rate-note"> + ${{ turn.parsedCompound!.dollarPerPiece }}/pc (→ $ field)</span>
                          } @else if (turn.parsedCompound!.hasNonPieceSpecific) {
                            <span class="rate-note"> + specific duty (check $ field)</span>
                          }
                          <span class="rate-src" title="From compound rate: {{ turn.htsRate!.rateText }}">USITC compound</span>
                        </span>
                      } @else if (turn.htsRate?.found && turn.htsRate!.rateText) {
                        <span class="rate-item">
                          MFN: <strong>{{ turn.htsRate!.rateText }}</strong>
                          <span class="rate-note">(non-ad-valorem — enter manually)</span>
                        </span>
                      } @else if (turn.htsRate === null) {
                        <span class="rate-note">MFN lookup failed — check connection</span>
                      } @else {
                        <span class="rate-note">MFN: HTS code not in USITC schedule — verify and enter manually</span>
                      }

                      @if (turn.section301?.found) {
                        <span class="rate-sep">+</span>
                        <span class="rate-item s301">
                          {{ turn.section301!.list }}: <strong>{{ turn.section301!.rate }}%</strong>
                          @if (turn.section301!.source) {
                            <span class="rate-src" title="{{ turn.section301!.source === 'override' ? 'From admin override' : 'From parsed USTR PDF' }}">{{ turn.section301!.source === 'override' ? 'override' : 'PDF' }}</span>
                          }
                        </span>
                      } @else if (turn.section301 === null) {
                        <span class="rate-note">Section 301 data not uploaded</span>
                      } @else if (turn.section301?.found === false) {
                        <span class="rate-note">Not on any Section 301 list</span>
                      }
                    </div>

                    <!-- Verification details — collapsed by default -->
                    @if (turn.section301?.found && turn.section301!.description) {
                      <details class="rate-details">
                        <summary>Section 301 source text</summary>
                        <p class="rate-source-text">"{{ turn.section301!.description }}"</p>
                        @if (turn.section301!.source !== 'override') {
                          <p class="rate-source-hint">If this looks wrong, go to Editor → Section 301 Overrides to correct it.</p>
                        }
                      </details>
                    }

                    <button mat-raised-button color="primary" class="apply-btn" type="button"
                            (click)="applyClassification(turn)"
                            [disabled]="!canEditDuty"
                            [matTooltip]="canEditDuty ? '' : 'View-only role — cannot apply changes.'">
                      Apply to breakdown
                    </button>

                    <!-- Reasoning + token telemetry footer -->
                    @if (turn.reasoningContent || turn.usage) {
                      <div class="turn-footer">
                        @if (turn.reasoningContent) {
                          <button type="button" class="reasoning-toggle" (click)="turn.showReasoning = !turn.showReasoning">
                            <mat-icon>{{ turn.showReasoning ? 'expand_less' : 'psychology' }}</mat-icon>
                            {{ turn.showReasoning ? 'Hide reasoning' : 'Show reasoning' }}
                          </button>
                        }
                        @if (turn.usage) {
                          <span class="usage-line" [title]="'prompt: ' + (turn.usage.prompt_tokens || 0) + ', total: ' + (turn.usage.total_tokens || 0)">
                            {{ formatUsage(turn.usage, turn.cost) }}
                          </span>
                        }
                      </div>
                      @if (turn.showReasoning && turn.reasoningContent) {
                        <pre class="reasoning-block">{{ turn.reasoningContent }}</pre>
                      }
                    }
                  </div>
                } @else {
                  <!-- Regular message bubble + optional reasoning/usage footer -->
                  <div class="chat-bubble">{{ turn.text }}</div>
                  @if ((turn.reasoningContent || turn.usage) && turn.role === 'ai') {
                    <div class="turn-footer turn-footer--bubble">
                      @if (turn.reasoningContent) {
                        <button type="button" class="reasoning-toggle" (click)="turn.showReasoning = !turn.showReasoning">
                          <mat-icon>{{ turn.showReasoning ? 'expand_less' : 'psychology' }}</mat-icon>
                          {{ turn.showReasoning ? 'Hide reasoning' : 'Show reasoning' }}
                        </button>
                      }
                      @if (turn.usage) {
                        <span class="usage-line">{{ formatUsage(turn.usage, turn.cost) }}</span>
                      }
                    </div>
                    @if (turn.showReasoning && turn.reasoningContent) {
                      <pre class="reasoning-block">{{ turn.reasoningContent }}</pre>
                    }
                  }
                }
              </div>
            }
            <div #chatBottom></div>
          </div>
        }

        <!-- Loading indicator -->
        @if (aiLoading) {
          <div class="ai-thinking">
            <mat-spinner [diameter]="16"></mat-spinner>
            <span>Thinking…</span>
          </div>
        }

        <!-- Chat input -->
        @if (!aiLoading && !aiError && aiInitialised) {
          <div class="ai-input-row">
            <mat-form-field appearance="outline" class="ai-input">
              <mat-label>Answer or ask a follow-up…</mat-label>
              <input #chatInputRef matInput
                     [value]="chatInput"
                     (input)="onChatInput($event)"
                     (keydown)="onChatKeydown($event)"
                     [disabled]="aiLoading"
                     placeholder="e.g. It is decorative, not a toy" />
            </mat-form-field>
            <button mat-raised-button color="primary" type="button" class="ai-send-btn"
                    (click)="sendChatMessage()" [disabled]="aiLoading || !chatInput.trim()"
                    [matTooltip]="!chatInput.trim() ? 'Type a message first' : ''">
              Send
            </button>
          </div>
        }

        <p class="ai-hint">
          The AI classifies using CBP CROSS rulings first (binding authority), then HTS heading analysis.
          MFN rate is from the bundled USITC schedule; Section 301 is from the uploaded USTR PDF.
          @if (latestClassificationCode) {
            <a [href]="'https://hts.usitc.gov/search?query=' + latestClassificationCode" target="_blank" rel="noopener">Open {{ latestClassificationCode }} on USITC ↗</a>
          } @else {
            <a href="https://hts.usitc.gov" target="_blank" rel="noopener">Open HTS ↗</a>
          }
          @if (sessionCostUsd > 0) {
            · Session cost: ${{ sessionCostUsd.toFixed(4) }}
          }
        </p>
      }
    </section>
  </div><!-- /.dialog-body -->

  <!-- CROSS Rulings lookup — full width below the two-column body -->
  <section class="cross-section">
    <button mat-button class="cross-toggle-btn" type="button" (click)="toggleCross()">
      <mat-icon>{{ showCross ? 'expand_less' : 'policy' }}</mat-icon>
      {{ showCross ? 'Hide CROSS lookup' : 'Look up HTS ruling (CROSS)' }}
    </button>

    @if (showCross) {
      <div class="cross-search-row">
        <mat-form-field appearance="outline" class="cross-input">
          <mat-label>HTS code or product description</mat-label>
          <input matInput [(ngModel)]="crossTerm" (keydown)="onCrossKeydown($event)"
                 placeholder="e.g. 9505.10 or vinyl figurine" />
        </mat-form-field>
        <button mat-raised-button color="primary" type="button" class="cross-search-btn"
                (click)="searchCross()" [disabled]="crossLoading || !crossTerm.trim()"
                [matTooltip]="crossLoading ? 'Search in progress…' : (!crossTerm.trim() ? 'Enter an HTS code or product description first' : '')">
          @if (crossLoading) { <mat-spinner [diameter]="18" style="display:inline-block"></mat-spinner> }
          @if (!crossLoading) { Search }
        </button>
      </div>

      <p class="cross-hint">
        CROSS rulings show how CBP has classified similar products. Use the HTS code to confirm classification
        then enter the applicable duty rate above.
        <a href="https://rulings.cbp.gov" target="_blank" rel="noopener">Open CROSS ↗</a>
      </p>

      @if (crossError) {
        <p class="cross-error">{{ crossError }}</p>
      }

      @if (crossResults.length > 0) {
        <p class="cross-count">Showing {{ crossResults.length }} of {{ crossTotal | number }} rulings</p>
        <div class="cross-results">
          @for (ruling of crossResults; track ruling.rulingNumber) {
            <div class="cross-ruling" (click)="openRuling(ruling.rulingNumber)">
              <div class="ruling-header">
                <span class="ruling-number">{{ ruling.rulingNumber }}</span>
                <span class="ruling-date">{{ ruling.rulingDate | date:'MMM d, y' }}</span>
              </div>
              <p class="ruling-subject">{{ ruling.subject }}</p>
              @if (ruling.tariffs?.length) {
                <div class="ruling-tariffs">
                  @for (t of ruling.tariffs; track t) {
                    <mat-chip class="hts-chip">{{ t }}</mat-chip>
                  }
                </div>
              }
            </div>
          }
        </div>
      }
    }
  </section>

  <section class="actions-section">
    <button mat-raised-button color="accent" class="action-btn" (click)="onCancel()">
      {{ canEditDuty ? 'Cancel' : 'Close' }}
    </button>
    @if (canEditDuty) {
      <button mat-raised-button color="accent" class="action-btn" (click)="onSave()">
        Save
      </button>
    }
  </section>
</div>

