const { normaliseUsage } = require('../../helpers/cache-metrics');

describe('cache-metrics helper', () => {
  test('normalizes OpenAI/OpenRouter/Qwen prompt_tokens_details cache fields', () => {
    const usage = normaliseUsage({
      prompt_tokens: 3000,
      completion_tokens: 100,
      total_tokens: 3100,
      prompt_tokens_details: {
        cached_tokens: 2048,
        cache_creation_input_tokens: 512,
      },
    });

    expect(usage.prompt_cache_hit_tokens).toBe(2048);
    expect(usage.prompt_cache_creation_tokens).toBe(512);
    expect(usage.prompt_cache_miss_tokens).toBe(440);
    expect(usage.prompt_cache_hit_rate_pct).toBe(68.3);
    expect(usage.cache_stats).toMatchObject({
      hit_tokens: 2048,
      miss_tokens: 440,
      creation_tokens: 512,
      telemetry_available: true,
    });
  });

  test('preserves DeepSeek native hit and miss token fields', () => {
    const usage = normaliseUsage({
      prompt_tokens: 1000,
      completion_tokens: 50,
      total_tokens: 1050,
      prompt_cache_hit_tokens: 900,
      prompt_cache_miss_tokens: 100,
    });

    expect(usage.prompt_cache_hit_tokens).toBe(900);
    expect(usage.prompt_cache_miss_tokens).toBe(100);
    expect(usage.prompt_cache_creation_tokens).toBe(0);
    expect(usage.prompt_cache_telemetry_available).toBe(true);
  });

  test('marks cache telemetry unavailable when provider only returns token totals', () => {
    const usage = normaliseUsage({
      prompt_tokens: 750,
      completion_tokens: 25,
      total_tokens: 775,
    });

    expect(usage.prompt_cache_hit_tokens).toBe(0);
    expect(usage.prompt_cache_miss_tokens).toBe(750);
    expect(usage.prompt_cache_telemetry_available).toBe(false);
  });
});

