  afterEach(() => {
    delete process.env.DASHSCOPE_API_KEY;
    delete process.env.QWEN_API_KEY;
    delete process.env.QWEN_BASE_URL;
    delete process.env.DASHSCOPE_BASE_URL;
  });

  test('maps OpenRouter-style qwen IDs to native Model Studio IDs', () => {
    expect(toNativeModelId('qwen/qwen-plus')).toBe('qwen-plus');
    expect(toNativeModelId('qwen-plus')).toBe('qwen-plus');
  });

  test('adds explicit cache markers to system and first-turn user messages', () => {
    const result = _applyCachingMarkers([
