  test('listUserModels calls /models with bearer token', async () => {
    axios.get.mockResolvedValue({ data: { data: [{ id: 'anthropic/claude-3.5-haiku' }] } });
    const result = await listUserModels();
    expect(axios.get).toHaveBeenCalledWith(
      'https://openrouter.ai/api/v1/models/user',
      expect.objectContaining({
        headers: expect.objectContaining({ Authorization: 'Bearer sk-or-test-key' }),
