    await expect(listUserModels()).rejects.toThrow('OPENROUTER_API_KEY is not configured');
  });

  test('listUserModels propagates HTTP errors from OpenRouter', async () => {
    axios.get.mockRejectedValue(Object.assign(new Error('Unauthorized'), { response: { status: 401 } }));
    await expect(listUserModels()).rejects.toMatchObject({ response: { status: 401 } });
  });

